const itens = $input.all();
let catalogoTexto = "CATÁLOGO ATUALIZADO EM TEMPO REAL:\n\n";

for (const item of itens) {
  const row = item.json;

  // Convertendo estoque para número para garantir a lógica
  const estoqueAtual = parseInt(row.Estoque);

  // Só adiciona ao catálogo se tiver estoque (> 0)
  if (estoqueAtual > 0) {
    catalogoTexto += `Produto: ${row.Produto}\n`;

    // CORREÇÃO: Acessando a chave com cedilha "Preço"
    catalogoTexto += `Preço: R$ ${row["Preço"]}\n`; 

    catalogoTexto += `Descrição: ${row.Descricao}\n`;

    // Adiciona o link da imagem se existir na planilha
    if (row.Imagem) {
      catalogoTexto += `URL da Imagem: ${row.Imagem}\n`;
    }

    // Gatilho de escassez (Alerta Interno para a IA)
    if (estoqueAtual <= 5) {
      catalogoTexto += `[Alerta Interno: Restam apenas ${estoqueAtual} unidades, use gatilho de urgência de forma sutil]\n`;
    }

    catalogoTexto += `\n`;
  }
}

return [{ json: { catalogoFormatado: catalogoTexto } }];

// Puxamos o carrinho e as linhas da planilha
const output = $('AI Agent de Respostas').item.json.output;
const carrinho = output.carrinho || [];
const linhasPlanilha = $('Verifica Planilha Controle Produtos').all(); 

let updates = [];

// Para cada produto comprado, calculamos o novo estoque
for (const comprado of carrinho) {

    // Busca flexível: converte tudo para minúsculo e checa se um nome contém o outro
    const produtoBanco = linhasPlanilha.find(p => {
        if (!p.json.Produto) return false;

        const nomePlanilha = p.json.Produto.toLowerCase().trim();
        const nomeComprado = comprado.produto.toLowerCase().trim();

        // Ex: "creatina monohidratada (300g)" contém "creatina monohidratada"
        return nomePlanilha.includes(nomeComprado) || nomeComprado.includes(nomePlanilha);
    });

    if (produtoBanco) {
        const estoqueAtual = parseInt(produtoBanco.json.Estoque) || 0;
        const novaQuantidade = estoqueAtual - comprado.quantidade;

        updates.push({
            json: {
                // IMPORTANTE: Passamos o nome EXATO que está no banco de dados
                Produto: produtoBanco.json.Produto, 
                Quantidade_Comprada: comprado.quantidade,
                Novo_Estoque: novaQuantidade > 0 ? novaQuantidade : 0
            }
        });
    }
}

return updates;

