// Pegamos a saída da IA
const output = $('AI Agent de Respostas').item.json.output;

// Extraímos as variáveis
const mensagens = output.mensagens || [];
const imagem = output.imagem || "";
const escalar = output.escalar || false;
const objetivo = output.objetivo || "Indefinido";

let returnItems = [];

// Transforma cada frase do Array em um item separado no n8n
mensagens.forEach((msg, index) => {
    returnItems.push({
        json: {
            texto: msg,
            // Envia a imagem apenas na PRIMEIRA iteração (index 0)
            imagem_atual: index === 0 ? imagem : "",
            escalar_atual: escalar,
            objetivo_atual: objetivo
        }
    });
});

// Se a IA por acaso não gerar mensagens (falha), enviamos um fallback
if (returnItems.length === 0) {
    returnItems.push({
        json: {
            texto: "Entendido!",
            imagem_atual: imagem,
            escalar_atual: escalar,
            objetivo_atual: objetivo
        }
    });
}

return returnItems;

